Here's a React component for our checkout form. Can you generate a Java Playwright page object model for it? We're using semantic selectors (ARIA roles and labels).

```jsx
import React, { useState } from 'react';

function CheckoutForm({ onSubmit }) {
  const [formData, setFormData] = useState({
    firstName: '', lastName: '', email: '', cardNumber: '', expiry: '', cvv: ''
  });
  const [errors, setErrors] = useState({});

  return (
    <div className="checkout-form">
      <h2>Payment Details</h2>
      <div className="form-row">
        <input
          type="text"
          aria-label="First name"
          placeholder="First name"
          value={formData.firstName}
          onChange={e => setFormData({...formData, firstName: e.target.value})}
        />
        <input
          type="text"
          aria-label="Last name"
          placeholder="Last name"
          value={formData.lastName}
          onChange={e => setFormData({...formData, lastName: e.target.value})}
        />
      </div>
      <input
        type="email"
        aria-label="Email address"
        placeholder="Email"
        value={formData.email}
      />
      <input
        type="text"
        aria-label="Card number"
        placeholder="Card number"
        data-testid="card-number"
        value={formData.cardNumber}
      />
      <div className="form-row">
        <input type="text" aria-label="Expiry date" placeholder="MM/YY" value={formData.expiry} />
        <input type="text" aria-label="CVV" placeholder="CVV" value={formData.cvv} />
      </div>
      {Object.keys(errors).length > 0 && (
        <div className="error-summary" role="alert">
          Please fix the errors below.
        </div>
      )}
      <button type="button" className="btn-secondary" onClick={() => window.history.back()}>
        Back to cart
      </button>
      <button type="submit" className="btn-primary" data-testid="place-order-btn">
        Place order
      </button>
    </div>
  );
}
